  const next = [...existing];
  const { masked, restore } = maskCodeRegionsForRelayCapture(buffer);
  let m: RegExpExecArray | null;
  RELAY_DELEGATE_RE.lastIndex = 0;
  while ((m = RELAY_DELEGATE_RE.exec(masked)) !== null) {
    const goal = m[2]?.trim() ?? "";
    if (isRelayDelegatePlaceholderGoal(goal)) continue;
    const token = restore(m[0]);
    if (!next.includes(token)) next.push(token);
  }
  return next;
}

/**
 * Resume 候選決策：flag on + registry 有記錄 + agent command 一致 +
 * backend key 一致才回 sessionId。任何不一致都靜默走 fresh（防呆優先）。
 * 獨立成 export 函式是為了 smoke test 可直測，不需拉起 SessionManager。
 */
export async function resolveResumeCandidate(
  chatId: number,
  backend: AcpBackendDef | undefined,
  agentCommand: string,
): Promise<string | undefined> {
  if (!config.acpSessionResume) return undefined;
  const rec = await loadResumable(chatId);
  if (!rec) return undefined;
  if (rec.agentCommand !== agentCommand) return undefined;
  if (rec.backendKey !== (backend?.key ?? "")) return undefined;
  return rec.sessionId;
}

