import { readFile, writeFile, unlink } from "node:fs/promises";
import path from "node:path";
import { config } from "./config.js";
import { loadFacts, buildPreambleWithBreakdown, buildLocalPreamble } from "./memory.js";
import { formatActiveRelayTasksForPreamble } from "./working-state.js";
import { petState } from "./pet-server.js";
import { AcpProvider, DirectProvider, resolveBaseUrl, type Provider, type ProviderType, type SessionUpdate } from "./provider/index.js";
import { logEvent } from "./event-log.js";
import { recordSeqObservation, appendToolName, TURN_MARKER } from "./tool-observer.js";
import { exportSession, saveArchive, type SessionArchive } from "./session-archive.js";
import { loadAcpProviders, type AcpBackendDef } from "./acp-providers.js";
import { loadResumable, saveResumable, clearResumable } from "./session-registry.js";

const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;

// ─── Pinned agent persistence ─────────────────────────────────────────────────
const PINNED_AGENT_PATH = path.join(config.memoryDir, "config", "pinned-agent.json");

async function loadPinnedAgents(): Promise<Map<number, string>> {
  try {
    const raw = await readFile(PINNED_AGENT_PATH, "utf8");
    const obj: Record<string, string> = JSON.parse(raw);
    const map = new Map<number, string>();
    for (const [k, v] of Object.entries(obj)) {
      const chatId = Number(k);
      if (!isNaN(chatId) && v) map.set(chatId, v);
    }
    return map;
  } catch {
    return new Map();
  }
}

async function savePinnedAgents(map: Map<number, string>): Promise<void> {
  const obj: Record<string, string> = {};
  for (const [k, v] of map) obj[String(k)] = v;
  await writeFile(PINNED_AGENT_PATH, JSON.stringify(obj, null, 2), "utf8");
}
