// ─── Token estimation ───────────────────────────────────────────────────────

export function estimateTokens(text: string): number;
export function estimateTokens(chars: number): number;
export function estimateTokens(input: string | number): number {
  if (typeof input === "number") return Math.ceil(input / 4);
  try {
    return tiktokenEncode(input).length;
  } catch {
    // Fallback if tokenizer rejects special tokens (e.g. <|im_start|> from local models)
    return Math.ceil(input.length / 4);
  }
}

export function pct(tok: number): string {
  const limit = config.contextWindowTokens;
  if (!limit) return "";
  return ((tok / limit) * 100).toFixed(1) + "%";
}

