export async function handleReset(ctx: Context): Promise<void> {
  const { isAllowed, sessions, saveTranscript } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const arg = ((ctx as any).match?.trim?.() ?? "").toLowerCase();
  const clean = arg === "clean" || arg === "fresh";

  const session = sessions.peek(chatId);
  if (session && session.history.length > 0) {
    try {
      const filename = await saveTranscript(session);
      await ctx.reply(`Saved → sessions/${filename}`);
    } catch {}
  }
  await sessions.drop(chatId, "reset");
  clearDedupCache(chatId);

  // Clean mode: delete archive + working-state so next session starts fresh.
  if (clean) {
    const { deleteArchive } = await import("../session-archive.js");
    const { unlink } = await import("node:fs/promises");
    const path = await import("node:path");
    const { config } = await import("../config.js");
    await deleteArchive(chatId);
    await unlink(path.join(config.memoryDir, `working-state-${chatId}.md`)).catch(() => {});
    await ctx.reply("Session reset (clean). 下次對話不會帶入上次上下文。");
  } else {
    await ctx.reply("Session reset.");
  }
}

export async function handleCancel(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const arg = (ctx as any).match?.trim?.() ?? "";

  if (arg.toLowerCase() === "all") {
    sessions.enableDropAll(chatId);
    sessions.cancel(chatId);
    await ctx.reply("✅ Cancel all: 已取消當前回合，排隊中的訊息將被丟棄。");
    return;
  }

  const session = sessions.peek(chatId);
  const placeholderMsgId = session?._placeholderMsgId;
  sessions.cancel(chatId);

  // Edit the placeholder to show partial output + cancellation notice
  if (placeholderMsgId) {
    const partial = (session!.buffer || "").trim();
    const text = partial
      ? `${partial}\n\n⛔ _(已取消)_`
      : "⛔ 已取消。";
    try {
      await ctx.api.editMessageText(chatId, placeholderMsgId, text);
    } catch { /* message may already be gone or identical */ }
  }
  await ctx.reply("✅ 已取消，可以繼續對話。");
}


