// ─── /handoff ───────────────────────────────────────────────────────────────

export async function handleHandoff(ctx: Context): Promise<void> {
  const { isAllowed, sessions, saveTranscript } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const uid = ctx.from?.id;
  const rawArgs =
    typeof ctx.match === "string"
      ? ctx.match
      : ctx.message && "text" in ctx.message && typeof ctx.message.text === "string"
        ? ctx.message.text.replace(/^\/(?:handoff|收工)(?:@\w+)?\s*/i, "")
        : "";
  const opts = parseHandoffArgs(rawArgs);
  const session = sessions.peek(chatId);
  if (!session) {
    await ctx.reply("No active session to hand off.");
    return;
  }
  if (session.history.length === 0) {
    await ctx.reply("No conversation history to hand off.");
    return;
  }
  if (session.inflight) {
    await ctx.reply(
      "⏳ 上一個回合還在進行中，無法同時跑 /handoff。請等它結束，或先 /cancel。",
    );
    return;
  }

  const goal = await goalStore.get(config.memoryDir, chatId).catch(() => null);
  if (goal?.status === "active" && !opts.keep) {
    await ctx.reply(
      "🎯 目前 /goal 仍在 active。為避免中斷目標迴圈，請改用 `/handoff keep` 只存交接，或先 `/goal clear` 後再 `/handoff`。",
      { parse_mode: "Markdown" },
    );
    return;
  }

  let savedFile: string | undefined;
  try {
    savedFile = await saveTranscript(session);
  } catch (err) {
    console.error(`[handoff] pre-save failed for chat ${chatId}:`, err);
  }

  const notice = await ctx.reply(
    opts.keep
      ? "📦 產生 handoff（保留目前 session）…"
      : "📦 產生 handoff，完成後會結束目前 session…",
  );

  sessions.resetTurn(session);
  session.inflight = true;
  try {
    await session.client.prompt(buildHandoffPrompt(session));
  } catch (err) {
    await ctx.api.editMessageText(
      chatId,
      notice.message_id,
      `❌ handoff 產生失敗：${(err as Error).message}`,
    );
    return;
  } finally {
    session.inflight = false;
    sessions.clearInactivityTimer(session);
  }

  const markdown = session.buffer.trim();
  if (!markdown) {
    await ctx.api.editMessageText(chatId, notice.message_id, "❌ handoff 產生失敗：agent 沒有輸出內容。");
    return;
  }

  let handoff;
  try {
    handoff = await writeHandoffFile(config.memoryDir, chatId, markdown);
  } catch (err) {
    await ctx.api.editMessageText(
      chatId,
      notice.message_id,
      `❌ handoff 寫檔失敗：${(err as Error).message}`,
    );
    return;
  }

  let addedFacts = 0;
  if (uid && handoff.factCandidates.length > 0) {
    try {
      addedFacts = await appendFactsDedup(uid, handoff.factCandidates);
    } catch (err) {
      console.error(`[handoff] appendFactsDedup failed for chat ${chatId}:`, err);
    }
  }

  if (!opts.keep) {
    try {
      await sessions.drop(chatId);
    } catch (err) {
      console.error(`[handoff] sessions.drop failed for chat ${chatId}:`, err);
      await ctx.api.editMessageText(
        chatId,
        notice.message_id,
        `⚠️ handoff 已寫入，但 session reset 失敗：${(err as Error).message}\n` +
          `${handoff.relativePath}\n` +
          `facts: ${addedFacts}/${handoff.factCandidates.length}`,
      );
      return;
    }
  }

  let backupLine = "";
  if (opts.backup) {
    try {
      const res = await runBackup();
      backupLine = res.ok
        ? res.commit
          ? `\nbackup: ${res.commit} (${res.filesChanged} files, ${res.elapsedSec}s)`
          : `\nbackup: no changes (${res.elapsedSec}s)`
        : `\nbackup failed: ${res.error ?? "(unknown)"}`;
    } catch (err) {
      backupLine = `\nbackup failed: ${(err as Error).message}`;
    }
  }

  await ctx.api.editMessageText(
    chatId,
    notice.message_id,
    `✅ handoff 完成${opts.keep ? "（session 保留）" : "（session 已結束）"}\n` +
      (savedFile ? `session: sessions/${savedFile}\n` : "") +
      `${handoff.relativePath}\n` +
      `facts: ${addedFacts}/${handoff.factCandidates.length}` +
      backupLine +
      (opts.keep ? "" : "\n下次訊息會建立新 session 並載入最新 memory。"),
  );
}


// ─── /sendfile ──────────────────────────────────────────────────────────────

export async function handleSendfile(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const raw = typeof ctx.match === "string" ? ctx.match.trim() : "";
  if (!raw) {
    await ctx.reply(
      "Usage: /sendfile <absolute-path>\n" +
        "Path must be under an allowed root (TG_SEND_ROOTS or ACP_SESSION_CWD).\n" +
        "Surrounding quotes are stripped."
    );
    return;
  }
  const unquoted = raw.replace(/^["'`]|["'`]$/g, "");
  const abs = path.resolve(unquoted);
  if (!isUnderAllowedRoot(abs)) {
    await ctx.reply(`Refused: path not under an allowed root.\n${abs}`);
    return;
  }
  let st;
  try {
    st = await stat(abs);
  } catch (err) {
    await ctx.reply(`Failed: ${(err as Error).message}`);
    return;
  }
  if (!st.isFile()) {
    await ctx.reply("Refused: not a regular file.");
    return;
  }
  const ext = path.extname(abs).toLowerCase();
  const asPhoto = IMG_EXT.has(ext) && ext !== ".png" && st.size <= 10 * 1024 * 1024;
  try {
    if (asPhoto) {
      try {
        await ctx.replyWithPhoto(new InputFile(abs));
      } catch {
        await ctx.replyWithDocument(new InputFile(abs));
      }
    } else {
      await ctx.replyWithDocument(new InputFile(abs));
    }
  } catch (err) {
    await ctx.reply(`Failed to send: ${(err as Error).message}`);
  }
}

// ─── /context ───────────────────────────────────────────────────────────────

export async function handleContext(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const session = sessions.peek(chatId);
  const lines = [
    `chat id: ${chatId}`,
    session?.acpBackend
      ? `agent: ${session.acpBackend}（/agent 切換，非 .env 預設）`
      : `agent: ${config.agent.command} ${config.agent.args.join(" ")}`,
    `cwd: ${config.sessionCwd}`,
    `idle timeout: ${Math.round(config.sessionIdleMs / 60000)} min`,
  ];
  if (!session) {
    lines.push("session: (none — next message will spawn one)");
  } else {
    const idleSec = Math.round((Date.now() - session.lastUsed) / 1000);
    const users = session.history.filter((h) => h.role === "user").length;
    const asst = session.history.filter((h) => h.role === "assistant").length;
    const pb = session.preambleBreakdown;
    const preTok = estimateTokens(session.memoryPreamble);
    const toolTok = estimateTokens(pb.toolNotes);
    const envTok = estimateTokens(pb.envBlock);
    const memTok = estimateTokens(pb.memoryBlock);
    const dailyTok = estimateTokens(pb.dailylogBlock);
    const userText = session.history.filter(h => h.role === "user").map(h => h.text).join("");
    const agentText = session.history.filter(h => h.role === "assistant").map(h => h.text).join("");
    const inTok = estimateTokens(userText);
    const outTok = estimateTokens(agentText);
    const totalTok = preTok + inTok + outTok;
    const share = (n: number) =>
      totalTok > 0 ? ((n / totalTok) * 100).toFixed(0) + "%" : "0%";
    lines.push(
      `session id: ${session.sessionId || "(pending)"}`,
      `status: ${session.client.isClosed ? "closed" : "active"}`,
      `idle: ${idleSec}s`,
      `history: ${users} user / ${asst} assistant`,
      `turn buffer: ${session.buffer.length} chars`,
      `tool events: ${session.toolLog.length}`,
      ``,
      `context use: ~${totalTok} / ${config.contextWindowTokens} tok (${pct(totalTok)})`,
      `  preamble:  ${preTok} tok (${share(preTok)})${session.resumed ? " — resumed session，preamble 凍在原 agent context 內（bridge 未重注，實際佔用不為 0）" : ""}`,
      `    tool notes: ${toolTok} tok`,
      `    env block:  ${envTok} tok`,
      `    memory:     ${memTok} tok`,
      `    dailylog:   ${dailyTok} tok`,
      `  user input: ${inTok} tok (${share(inTok)})`,
      `  agent out:  ${outTok} tok (${share(outTok)})`,
      `note: agent's own system prompt / skill index is not counted (bridge can't see it).`
    );
    if (session.usage) {
      lines.push(`agent-reported usage: ${JSON.stringify(session.usage)}`);
    }
  }
  await ctx.reply(lines.join("\n"));
}

// ─── /usage ─────────────────────────────────────────────────────────────────

export async function handleUsage(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const session = sessions.peek(ctx.chat!.id);
  if (!session) {
    await ctx.reply("No active session.");
    return;
  }
  const pb = session.preambleBreakdown;
  const preTok = estimateTokens(session.memoryPreamble);
  const toolTok = estimateTokens(pb.toolNotes);
  const envTok = estimateTokens(pb.envBlock);
  const memTok = estimateTokens(pb.memoryBlock);
  const userText = session.history.filter(h => h.role === "user").map(h => h.text).join("");
  const agentText = session.history.filter(h => h.role === "assistant").map(h => h.text).join("");
  const inTok = estimateTokens(userText);
  const outTok = estimateTokens(agentText);
  const totalTok = preTok + inTok + outTok;
  const share = (n: number) =>
    totalTok > 0 ? ((n / totalTok) * 100).toFixed(0) + "%" : "0%";
  const lines = [
    `context use (bridge-visible, approx):`,
    `  preamble:   ${preTok} tok (${share(preTok)})`,
    `    tool notes: ${toolTok} tok`,
    `    env block:  ${envTok} tok`,
    `    memory:     ${memTok} tok`,
    `  user input: ${inTok} tok (${share(inTok)})`,
    `  agent out:  ${outTok} tok (${share(outTok)})`,
    `  total:      ${totalTok} / ${config.contextWindowTokens} tok (${pct(totalTok)})`,
    `note: agent's own system prompt / skill index is not counted (bridge can't see it).`,
  ];
  if (session.usage) {
    lines.push(`agent-reported usage: ${JSON.stringify(session.usage)}`);
  } else {
    lines.push(`agent-reported usage: (not provided by agent)`);
  }
  await ctx.reply(lines.join("\n"));
}


// ─── /backup ────────────────────────────────────────────────────────────────

export async function handleBackup(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const notice = await ctx.reply("☁️ 開始備份（robocopy + git push）…");
  try {
    const res = await runBackup();
    if (!res.ok) {
      await ctx.api.editMessageText(
        chatId,
        notice.message_id,
        `❌ 備份失敗：\n${res.error ?? "(未知錯誤)"}`,
      );
      return;
    }
    const lines: string[] = [];
    if (res.commit) {
      lines.push(`✅ 備份完成（${res.elapsedSec}s）`);
      lines.push(`commit: \`${res.commit}\` (${res.filesChanged} 個檔案)`);
      lines.push(res.summary);
    } else {
      lines.push(`✅ 無異動，備份跳過 commit（${res.elapsedSec}s）`);
      if (res.summary && res.summary !== "No changes") {
        lines.push(res.summary);
      }
    }
    await ctx.api.editMessageText(
      chatId,
      notice.message_id,
      lines.join("\n"),
    );
  } catch (err) {
    await ctx.api.editMessageText(
      chatId,
      notice.message_id,
      `❌ 備份失敗：${(err as Error).message}`,
    );
  }
}

// ─── /skillusage ────────────────────────────────────────────────────────────

export async function handleSkillUsage(ctx: Context): Promise<void> {
  const { isAllowed, formatRelative } = deps();
  if (!isAllowed(ctx)) return;
  const skillDir = detectSkillDir();
  if (skillDir.startsWith("(")) {
    await ctx.reply(`📚 Skills overview\n\n⚠️ SKILL_DIR 未設定：${skillDir}`);
    return;
  }

  let sweep: { added: string[]; newlyOrphaned: string[]; deOrphaned: string[] };
  try {
    sweep = await usageStore.migrateFromDisk(skillDir);
  } catch (err) {
    await ctx.reply(
      `📚 Skills overview\n\n⚠️ 讀取 ${skillDir} 失敗：${(err as Error).message}`,
    );
    return;
  }

  const all = await usageStore.listAll(skillDir);
  const entries = Object.entries(all.skills).map(([name, e]) => ({ name, ...e }));
  const total = entries.length;
  if (total === 0) {
    await ctx.reply(
      `📚 Skills overview — 0 skills at ${skillDir}\n\n(目錄裡沒有任何 SKILL.md 檔)`,
    );
    return;
  }

  const pinned = entries.filter((e) => e.pinned);
  const orphaned = entries.filter((e) => e.orphan);
  const neverUsed = entries.filter((e) => e.use_count === 0 && !e.orphan);
  const recentlyAdded = [...entries]
    .filter((e) => !e.orphan)
    .sort((a, b) => b.created_at.localeCompare(a.created_at))
    .slice(0, 5);
  const topUsed = [...entries]
    .filter((e) => e.use_count > 0)
    .sort((a, b) => b.use_count - a.use_count)
    .slice(0, 5);

  const lines: string[] = [];
  lines.push(`📚 Skills overview — ${total} skills at ${skillDir}`);
  lines.push("");
  if (sweep.added.length > 0) {
    lines.push(`➕ 新增追蹤：${sweep.added.join(", ")}`);
  }
  if (sweep.newlyOrphaned.length > 0) {
    lines.push(`⚠️ 新發現 orphan（SKILL.md 不見了）：${sweep.newlyOrphaned.join(", ")}`);
  }
  if (sweep.deOrphaned.length > 0) {
    lines.push(`♻️ 重現：${sweep.deOrphaned.join(", ")}`);
  }
  if (sweep.added.length + sweep.newlyOrphaned.length + sweep.deOrphaned.length > 0) {
    lines.push("");
  }

  if (pinned.length > 0) {
    lines.push(`📌 Pinned (${pinned.length}):`);
    for (const e of pinned) {
      const tag = e.notes ? ` — ${e.notes}` : "";
      lines.push(`  • ${e.name}${tag}`);
    }
    lines.push("");
  }

  if (topUsed.length > 0) {
    lines.push(`🔥 最常用 (${topUsed.length}):`);
    for (const e of topUsed) {
      const reasonTail = e.last_reason
        ? ` — ${e.last_reason.length > 40 ? e.last_reason.slice(0, 40) + "…" : e.last_reason}`
        : "";
      lines.push(`  • ${e.name}  (${e.use_count}×)${reasonTail}`);
    }
    lines.push("");
  }

  if (recentlyAdded.length > 0) {
    lines.push(`🆕 最近新增 (top 5):`);
    for (const e of recentlyAdded) {
      const d = new Date(e.created_at);
      const ago = formatRelative(d.getTime() - Date.now());
      lines.push(`  • ${e.name}  (${ago})`);
    }
    lines.push("");
  }

  if (neverUsed.length > 0) {
    lines.push(`💤 Bridge 端從未看到 agent 用過 (${neverUsed.length}):`);
    const names = neverUsed.map((e) => e.name).slice(0, 10);
    lines.push(`  ${names.join(", ")}${neverUsed.length > 10 ? ` …+${neverUsed.length - 10}` : ""}`);
    lines.push("");
  }

  if (orphaned.length > 0) {
    lines.push(`👻 Orphan entries (skill-usage.json 有但磁碟沒 SKILL.md) (${orphaned.length}):`);
    lines.push(`  ${orphaned.map((e) => e.name).join(", ")}`);
    lines.push("");
  }

  lines.push(
    "ℹ️ Note: bridge 端統計只在 agent 回覆帶 <<SKILL_USED>> token 時計數。" +
      "「從未看到使用」可能代表該 skill 真的沒用、或 agent 忘記加 token。",
  );

  for (const e of entries) {
    await usageStore.markListed(skillDir, e.name).catch(() => {});
  }

  const body = lines.join("\n");
  if (body.length > TG_MAX) {
    await ctx.reply(body.slice(0, TG_MAX - 20) + "\n… (trimmed)");
  } else {
    await ctx.reply(body);
  }
}

// ─── /pin + /unpin ──────────────────────────────────────────────────────────

export async function handlePin(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const raw = (typeof ctx.match === "string" ? ctx.match : "").trim();
  if (!raw) {
    await ctx.reply("用法：/pin <skill-name>\n例如：/pin ms-agent-long-term-memory");
    return;
  }
  const name = raw.split(/\s+/)[0];
  const skillDir = detectSkillDir();
  if (skillDir.startsWith("(")) {
    await ctx.reply(`⚠️ SKILL_DIR 未設定：${skillDir}`);
    return;
  }
  await usageStore.setPinned(skillDir, name, true);
  await ctx.reply(
    `📌 Pinned: ${name}\n` +
      `Note: pin flag 目前只是標記，bridge 尚未擋 agent 自動改 skill — ` +
      `等未來有 agent-writes-skill 能力時才會變成真的屏障。`,
  );
}

export async function handleUnpin(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const raw = (typeof ctx.match === "string" ? ctx.match : "").trim();
  if (!raw) {
    await ctx.reply("用法：/unpin <skill-name>");
    return;
  }
  const name = raw.split(/\s+/)[0];
  const skillDir = detectSkillDir();
  if (skillDir.startsWith("(")) {
    await ctx.reply(`⚠️ SKILL_DIR 未設定：${skillDir}`);
    return;
  }
  await usageStore.setPinned(skillDir, name, false);
  await ctx.reply(`📍 Unpinned: ${name}`);
}

