   145→ * - 路徑函式優先讀 process.env.MEMORY_DIR（可測試性），fallback config.memoryDir。
   146→ */
   147→import path from "node:path";
   148→import { readJsonOrDefault, atomicWriteJson } from "./atomicJson.js";
   149→import { config } from "./config.js";
   150→
   151→export interface ResumableSession {
   152→  /** ACP session id（session/new 的回傳值）。 */
   153→  sessionId: string;
   154→  /** /agent pin 的 backend key；.env agent 時為 ""。 */
   155→  backendKey: string;
   156→  /** spawn 的 agent command（backend/.env 變更時做防呆比對）。 */
   157→  agentCommand: string;
   158→  /** session/new 當時的 cwd（session/load 需帶同值）。 */
   159→  cwd: string;
   160→  /** 最後寫入時間（epoch ms）。 */
   161→  savedAt: number;
   162→}
   163→
   164→type RegistryFile = Record<string, ResumableSession>;
   165→
   166→function registryPath(): string {
   167→  const dir = process.env.MEMORY_DIR || config.memoryDir;
   168→  return path.join(dir, "config", "acp-session-registry.json");
   169→}
   170→
   171→export async function loadResumable(chatId: number): Promise<ResumableSession | null> {
   172→  const all = await readJsonOrDefault<RegistryFile>(registryPath(), {});
   173→  const rec = all[String(chatId)];
   174→  if (!rec || !rec.sessionId) return null;
   175→  return rec;
   176→}
   177→
   178→export async function saveResumable(chatId: number, rec: ResumableSession): Promise<void> {
   179→  const all = await readJsonOrDefault<RegistryFile>(registryPath(), {});
   180→  all[String(chatId)] = rec;
   181→  await atomicWriteJson(registryPath(), all);
   182→}
   183→
   184→export async function clearResumable(chatId: number): Promise<void> {
   185→  const all = await readJsonOrDefault<RegistryFile>(registryPath(), {});
   186→  if (!(String(chatId) in all)) return;
   187→  delete all[String(chatId)];
   188→  await atomicWriteJson(registryPath(), all);
   189→}
   190→```
