   231→// 支援 initialize / session/new / session/load（帶 replay）/ session/prompt。
   232→// env FAKE_ACP_NO_LOADCAP=1 時 initialize 不宣告 loadSession capability。
   233→// env FAKE_ACP_LOAD_FAIL=1 時 session/load 回 JSON-RPC error。
   234→import { createInterface } from "node:readline";
   235→
   236→const send = (obj) => process.stdout.write(JSON.stringify(obj) + "\n");
   237→const rl = createInterface({ input: process.stdin });
   238→
   239→rl.on("line", (line) => {
   240→  let msg;
   241→  try { msg = JSON.parse(line); } catch { return; }
   242→  if (!("method" in msg)) return; // ignore responses
   243→
   244→  if (msg.method === "initialize") {
   245→    send({ jsonrpc: "2.0", id: msg.id, result: {
   246→      protocolVersion: 1,
   247→      agentCapabilities: {
   248→        loadSession: process.env.FAKE_ACP_NO_LOADCAP === "1" ? false : true,
   249→      },
   250→    }});
   251→    return;
   252→  }
   253→  if (msg.method === "session/new") {
   254→    send({ jsonrpc: "2.0", id: msg.id, result: { sessionId: "sess_fake_new" } });
   255→    return;
   256→  }
   257→  if (msg.method === "session/load") {
   258→    if (process.env.FAKE_ACP_LOAD_FAIL === "1") {
   259→      send({ jsonrpc: "2.0", id: msg.id, error: { code: -32001, message: "session not found" } });
   260→      return;
   261→    }
   262→    const sid = msg.params?.sessionId ?? "";
   263→    // Replay 兩則歷史（含一個危險 token，驗證抑制）
   264→    send({ jsonrpc: "2.0", method: "session/update", params: {
   265→      sessionId: sid, update: { sessionUpdate: "user_message_chunk",
   266→        content: { type: "text", text: "舊訊息" } } }});
   267→    send({ jsonrpc: "2.0", method: "session/update", params: {
   268→      sessionId: sid, update: { sessionUpdate: "agent_message_chunk",
   269→        content: { type: "text", text: "舊回覆 <<ASK:old|a=別按>>" } } }});
   270→    send({ jsonrpc: "2.0", id: msg.id, result: null });
   271→    return;
   272→  }
   273→  if (msg.method === "session/prompt") {
   274→    send({ jsonrpc: "2.0", method: "session/update", params: {
   275→      sessionId: msg.params?.sessionId, update: { sessionUpdate: "agent_message_chunk",
   276→        content: { type: "text", text: "新回覆" } } }});
   277→    send({ jsonrpc: "2.0", id: msg.id, result: { stopReason: "end_turn" } });
   278→    return;
   279→  }
   280→  // 其他 method 一律回空物件
   281→  if ("id" in msg) send({ jsonrpc: "2.0", id: msg.id, result: {} });
   282→});
