   700→        backendKey: backend?.key ?? "",
   701→        agentCommand,
   702→        cwd: config.sessionCwd,
   703→        savedAt: Date.now(),
   704→      }).catch((err) => console.warn(`[session ${chatId}] saveResumable failed:`, err));
