import path from "node:path";
const toURL = (rel) => pathToFileURL(path.resolve(rel)).href;
const { saveResumable } = await import(toURL("dist/session-registry.js"));
const { resolveResumeCandidate } = await import(toURL("dist/sessionManager.js"));
await saveResumable(333, { sessionId: "sess_m", backendKey: "", agentCommand: "kiro-cli",
  cwd: process.cwd(), savedAt: Date.now() });
const hit = await resolveResumeCandidate(333, undefined, "kiro-cli");
const miss = await resolveResumeCandidate(333, undefined, "codex-acp");
console.log(JSON.stringify({ hit: hit ?? null, miss: miss ?? null }));
`;

// M1+M2: flag on → command 相符命中 / 不符落空
{
  const out = runM({ ACP_SESSION_RESUME: "true", MEMORY_DIR: mTmp }, mCode);
  let r = {};
  try { r = JSON.parse(out.split("\n").pop()); } catch {}
  check("M1 candidate hit", r.hit === "sess_m");
  check("M2 command mismatch → no resume", r.miss === null);
}

