/**
 * SessionRegistry — per-chat ACP session 持久化記錄（v2：多 session store）。
 *
 * v1（單筆）：idle/crash 後記住上一個 sessionId 供 session/load 恢復。
 * v2（本版）：升級為 multi-record store —— 同一 chat 可持有多個 named
 * session（一個 active、其餘 parked），支撐 /session 列表/切換/新建。
 *
 * 設計決策：
 * - 沿用原檔名 acp-session-registry.json，讀取時 shape 偵測自動 migration
 *   （舊 shape 無 version 欄位；一次性、冪等）。
 * - 既有三函式（loadResumable/saveResumable/clearResumable）簽名不變，
 *   內部委派 active record —— sessionManager 呼叫點與既有 smoke 零改動。
 *   clearResumable 語意刻意變窄：只清 active（/reset 不再毀掉 parked 對話）。
 * - 走 atomicJson（Windows EPERM retry + 壞檔容錯回空 store）。
 * - 只在 ACP_SESSION_RESUME=true 時被呼叫（呼叫端閘控），本模組不讀 flag。
 * - 路徑函式優先讀 process.env.MEMORY_DIR（可測試性），fallback config.memoryDir。
 * - 單人架構 + 原子寫，不做檔案鎖；多 user 需求出現時改 updateJson。
 */
import path from "node:path";
import crypto from "node:crypto";
import { readJsonOrDefault, atomicWriteJson } from "./atomicJson.js";
import { config } from "./config.js";

export interface ResumableSession {
  /** ACP session id（session/new 的回傳值）。 */
  sessionId: string;
  /** /agent pin 的 backend key；.env agent 時為 ""。 */
  backendKey: string;
  /** spawn 的 agent command（backend/.env 變更時做防呆比對）。 */
  agentCommand: string;
  /** session/new 當時的 cwd（session/load 需帶同值）。 */
  cwd: string;
  /** 最後寫入時間（epoch ms）。 */
  savedAt: number;
}

export interface SessionRecord extends ResumableSession {
  /** 短 id（隨機 8 hex），/session callback data 用。 */
  id: string;
  /** 顯示名稱。空字串 = 尚未命名（首則 user 訊息自動填）。 */
  name: string;
  createdAt: number;
}

interface ChatSessions {
  /** 指向 sessions 內某 id；create() 時 resume 的就是它。空字串 = 無 active。 */
  activeId: string;
  sessions: SessionRecord[];
}

interface StoreFileV2 {
  version: 2;
  chats: Record<string, ChatSessions>;
}

/** 每 chat session 數上限（達上限時 /session new 拒絕）。 */
export const MAX_SESSIONS_PER_CHAT = 8;

/** 自動命名長度上限（字元）。 */
const AUTO_NAME_MAX = 24;
/** 手動 rename 長度上限（inline keyboard label 安全值）。 */
const RENAME_MAX = 40;

function registryPath(): string {
  const dir = process.env.MEMORY_DIR || config.memoryDir;
  return path.join(dir, "config", "acp-session-registry.json");
}

function newId(): string {
  return crypto.randomBytes(4).toString("hex");
}

function isV2(raw: unknown): raw is StoreFileV2 {
  return !!raw && typeof raw === "object" &&
    (raw as { version?: unknown }).version === 2 &&
    typeof (raw as { chats?: unknown }).chats === "object";
}

/**
 * 讀 store。舊 shape（Record<chatId, ResumableSession>，無 version 欄位）
 * 自動 migration 成 v2 並寫回（僅在有舊資料時寫，避免平白建檔）。
 */
async function loadStore(): Promise<StoreFileV2> {
  const raw = await readJsonOrDefault<unknown>(registryPath(), () => ({}));
  if (isV2(raw)) return raw;

  const chats: Record<string, ChatSessions> = {};
  if (raw && typeof raw === "object") {
    for (const [chatId, rec] of Object.entries(raw as Record<string, ResumableSession>)) {
      if (!rec || typeof rec.sessionId !== "string" || !rec.sessionId) continue;
      const record: SessionRecord = {
        id: newId(),
        name: "",
        createdAt: rec.savedAt ?? Date.now(),
        sessionId: rec.sessionId,
        backendKey: rec.backendKey ?? "",
        agentCommand: rec.agentCommand ?? "",
        cwd: rec.cwd ?? "",
        savedAt: rec.savedAt ?? Date.now(),
      };
      chats[chatId] = { activeId: record.id, sessions: [record] };
    }
  }
  const store: StoreFileV2 = { version: 2, chats };
  if (Object.keys(chats).length > 0) {
    await atomicWriteJson(registryPath(), store);
  }
  return store;
}

async function saveStore(store: StoreFileV2): Promise<void> {
  await atomicWriteJson(registryPath(), store);
}

function chatOf(store: StoreFileV2, chatId: number): ChatSessions | undefined {
  return store.chats[String(chatId)];
}

function activeRecord(chat: ChatSessions | undefined): SessionRecord | undefined {
  if (!chat || !chat.activeId) return undefined;
  return chat.sessions.find((s) => s.id === chat.activeId);
}

// ─── Legacy API（sessionManager 呼叫點零改動）────────────────────────────────

export async function loadResumable(chatId: number): Promise<ResumableSession | null> {
  const rec = activeRecord(chatOf(await loadStore(), chatId));
  if (!rec || !rec.sessionId) return null;
  return {
    sessionId: rec.sessionId,
    backendKey: rec.backendKey,
    agentCommand: rec.agentCommand,
    cwd: rec.cwd,
    savedAt: rec.savedAt,
  };
}

/** Upsert active record：無 active 時建新 record 並設 active。 */
export async function saveResumable(chatId: number, rec: ResumableSession): Promise<void> {
  const store = await loadStore();
  const key = String(chatId);
  const chat = store.chats[key] ?? { activeId: "", sessions: [] };
  const active = activeRecord(chat);
  if (active) {
    Object.assign(active, rec);
  } else {
    const record: SessionRecord = { id: newId(), name: "", createdAt: Date.now(), ...rec };
    chat.sessions.push(record);
    chat.activeId = record.id;
  }
  store.chats[key] = chat;
  await saveStore(store);
}

/** 只移除 active record（parked 保留，activeId 清空 → 下次 create 走 fresh）。 */
export async function clearResumable(chatId: number): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat || !chat.activeId) return;
  chat.sessions = chat.sessions.filter((s) => s.id !== chat.activeId);
  chat.activeId = "";
  if (chat.sessions.length === 0) delete store.chats[String(chatId)];
  await saveStore(store);
}

// ─── Store API（/session 多 session 管理）────────────────────────────────────

export async function listSessions(
  chatId: number,
): Promise<{ activeId: string; sessions: SessionRecord[] }> {
  const chat = chatOf(await loadStore(), chatId);
  return { activeId: chat?.activeId ?? "", sessions: chat?.sessions ?? [] };
}

/** 切 active 到指定 record；id 不存在回 null（store 不變）。 */
export async function setActive(chatId: number, id: string): Promise<SessionRecord | null> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  const rec = chat?.sessions.find((s) => s.id === id);
  if (!chat || !rec) return null;
  chat.activeId = id;
  await saveStore(store);
  return rec;
}

/** activeId 清空（records 全保留）。/session new 用：park 後 create 走 fresh。 */
export async function clearActive(chatId: number): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat || !chat.activeId) return;
  chat.activeId = "";
  await saveStore(store);
}

export async function removeSession(chatId: number, id: string): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat) return;
  const before = chat.sessions.length;
  chat.sessions = chat.sessions.filter((s) => s.id !== id);
  if (chat.sessions.length === before) return;
  if (chat.activeId === id) chat.activeId = "";
  if (chat.sessions.length === 0) delete store.chats[String(chatId)];
  await saveStore(store);
}

export async function renameSession(chatId: number, id: string, name: string): Promise<boolean> {
  const store = await loadStore();
  const rec = chatOf(store, chatId)?.sessions.find((s) => s.id === id);
  if (!rec) return false;
  rec.name = sanitizeName(name, RENAME_MAX);
  await saveStore(store);
  return true;
}

/** Active record 的 name 為空時才寫入（冪等——resume 後重複觸發無害）。 */
export async function autoNameActive(chatId: number, candidate: string): Promise<void> {
  const store = await loadStore();
  const rec = activeRecord(chatOf(store, chatId));
  if (!rec || rec.name !== "") return;
  const name = sanitizeName(candidate, AUTO_NAME_MAX);
  if (!name) return;
  rec.name = name;
  await saveStore(store);
}

function sanitizeName(raw: string, max: number): string {
  return raw.replace(/\s+/g, " ").trim().slice(0, max);
}

