  if (active) {
    Object.assign(active, rec);
  } else {
    const record: SessionRecord = { id: newId(), name: "", createdAt: Date.now(), ...rec };
    chat.sessions.push(record);
    chat.activeId = record.id;
  }
  store.chats[key] = chat;
  await saveStore(store);
}

/** 只移除 active record（parked 保留，activeId 清空 → 下次 create 走 fresh）。 */
export async function clearResumable(chatId: number): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat || !chat.activeId) return;
  chat.sessions = chat.sessions.filter((s) => s.id !== chat.activeId);
  chat.activeId = "";
  if (chat.sessions.length === 0) delete store.chats[String(chatId)];
  await saveStore(store);
}

// ─── Store API（/session 多 session 管理）────────────────────────────────────

export async function listSessions(
  chatId: number,
): Promise<{ activeId: string; sessions: SessionRecord[] }> {
  const chat = chatOf(await loadStore(), chatId);
  return { activeId: chat?.activeId ?? "", sessions: chat?.sessions ?? [] };
}

/** 切 active 到指定 record；id 不存在回 null（store 不變）。 */
export async function setActive(chatId: number, id: string): Promise<SessionRecord | null> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  const rec = chat?.sessions.find((s) => s.id === id);
  if (!chat || !rec) return null;
  chat.activeId = id;
  await saveStore(store);
  return rec;
}

/** activeId 清空（records 全保留）。/session new 用：park 後 create 走 fresh。 */
export async function clearActive(chatId: number): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat || !chat.activeId) return;
  chat.activeId = "";
  await saveStore(store);
}

export async function removeSession(chatId: number, id: string): Promise<void> {
  const store = await loadStore();
  const chat = chatOf(store, chatId);
  if (!chat) return;
  const before = chat.sessions.length;
  chat.sessions = chat.sessions.filter((s) => s.id !== id);
  if (chat.sessions.length === before) return;
  if (chat.activeId === id) chat.activeId = "";
  if (chat.sessions.length === 0) delete store.chats[String(chatId)];
  await saveStore(store);
}

export async function renameSession(chatId: number, id: string, name: string): Promise<boolean> {
  const store = await loadStore();
  const rec = chatOf(store, chatId)?.sessions.find((s) => s.id === id);
  if (!rec) return false;
  rec.name = sanitizeName(name, RENAME_MAX);
  await saveStore(store);
  return true;
}

/** Active record 的 name 為空時才寫入（冪等——resume 後重複觸發無害）。 */
export async function autoNameActive(chatId: number, candidate: string): Promise<void> {
  const store = await loadStore();
  const rec = activeRecord(chatOf(store, chatId));
  if (!rec || rec.name !== "") return;
  const name = sanitizeName(candidate, AUTO_NAME_MAX);
  if (!name) return;
  rec.name = name;
  await saveStore(store);
}

function sanitizeName(raw: string, max: number): string {
  return raw.replace(/\s+/g, " ").trim().slice(0, max);
}

