  const base = { ...process.env, TELEGRAM_BOT_TOKEN: "dummy" };
  delete base.ACP_SESSION_RESUME;
  try {
    const out = execFileSync(process.execPath, ["--input-type=module", "-e", code], {
      env: { ...base, ...env },
      encoding: "utf8", cwd: process.cwd(), timeout: 15000,
    });
    return out.trim();
  } catch (e) {
    return `ERR:${e.stderr || e.message}`;
  }
}

const mTmp = mkdtempSync(path.join(tmpdir(), "resume-test-m-"));
