/**
 * /session command — 多 session 管理（列表 / 切換 / 新建 / 改名 / 關閉）。
 *
 * 借鏡 ai_multi_agent 的 SessionStore + inline keyboard。切換走
 * sessionManager.switchSession()（park 現行 → session/load 恢復目標）。
 * 依賴 ACP_SESSION_RESUME=true（切換本質需要 session/load）；flag off
 * 只回提示、不觸碰 store（BC-1）。
 *
 * Callback namespace：`sess:sw:<id>`（切換）、`sess:new`（新對話），
 * 由 index.ts callback dispatcher 的 "sess" 分支轉進 handleSessionCallback。
 */
import { Context, InlineKeyboard } from "grammy";
import { config } from "../config.js";
import {
  listSessions, renameSession, clearResumable, MAX_SESSIONS_PER_CHAT,
} from "../session-registry.js";
import { formatRelative } from "../utils.js";
import { deps } from "./deps.js";

const FLAG_OFF_HINT =
  "多 session 管理需要先在 .env 啟用 ACP_SESSION_RESUME=true（並重啟 bridge）。";

/** 組列表訊息 + keyboard。sessions 空時 keyboard 只剩「新對話」。 */
async function buildListView(
  chatId: number,
): Promise<{ text: string; keyboard: InlineKeyboard | null }> {
  const { activeId, sessions } = await listSessions(chatId);
  const sorted = [...sessions].sort((a, b) => {
    if (a.id === activeId) return -1;
    if (b.id === activeId) return 1;
    return b.savedAt - a.savedAt;
  });
  const lines = [`🗂 Sessions (${sessions.length}/${MAX_SESSIONS_PER_CHAT})`];
  for (const rec of sorted) {
    const mark = rec.id === activeId ? "✅" : "💤";
    const name = rec.name || "(未命名)";
    lines.push(`${mark} ${name} (${rec.id}) — ${formatRelative(Date.now() - rec.savedAt)}前`);
  }
  if (sessions.length === 0) {
    lines.push("（尚無記錄 — 發訊息或按「新對話」即可開始）");
  }
  const kb = new InlineKeyboard();
  let rows = 0;
  for (const rec of sorted) {
    if (rec.id === activeId) continue; // active 不需要切換按鈕
    kb.text(`💤 ${rec.name || rec.id}`, `sess:sw:${rec.id}`).row();
    rows++;
  }
  if (sessions.length < MAX_SESSIONS_PER_CHAT) {
    kb.text("➕ 新對話", "sess:new");
    rows++;
  }
  return { text: lines.join("\n"), keyboard: rows > 0 ? kb : null };
}

export async function handleSession(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;
  if (!config.acpSessionResume) {
    await ctx.reply(FLAG_OFF_HINT);
    return;
  }

  const raw = (typeof ctx.match === "string" ? ctx.match : "").trim();
  const [sub, ...rest] = raw.split(/\s+/);
  const arg = rest.join(" ").trim();

  // /session — 列表 + keyboard
  if (!sub) {
    const { text, keyboard } = await buildListView(chatId);
    await ctx.reply(text, keyboard ? { reply_markup: keyboard } : undefined);
    return;
  }

  // /session new [name]
  if (sub === "new") {
    try {
      await ctx.reply("🔄 正在開新對話…");
      await sessions.newSession(chatId, userId, arg || undefined);
      await ctx.reply(`✅ 已開新對話${arg ? `：${arg}` : "（首則訊息會自動命名）"}`);
    } catch (err) {
      await ctx.reply(`❌ ${(err as Error).message}`);
    }
    return;
  }

  // /session rename <name> — 改 active record 名稱
  if (sub === "rename") {
    if (!arg) {
      await ctx.reply("用法：/session rename <新名稱>");
      return;
    }
    const { activeId } = await listSessions(chatId);
    if (!activeId) {
      await ctx.reply("目前沒有 active session 記錄（先發訊息建立 session）。");
      return;
    }
    await renameSession(chatId, activeId, arg);
    await ctx.reply(`✅ 已改名：${arg}`);
    return;
  }

  // /session close — 關閉 active（fresh 意圖語意：清 active record，parked 不動）
  if (sub === "close") {
    const live = sessions.peek(chatId);
    if (live?.inflight) {
      await ctx.reply("⚠️ 目前有 turn 進行中，請等它完成或先 /cancel。");
      return;
    }
    if (live) {
      await sessions.drop(chatId, "manual");
    } else {
      // 無活 subprocess（idle 已收掉）但 record 可能還在 → 直接清 active record
      await clearResumable(chatId);
    }
    await ctx.reply("✅ 已關閉目前對話（parked 對話保留，/session 可查看）。");
    return;
  }

  await ctx.reply("用法：/session（列表）| /session new [名稱] | /session rename <名稱> | /session close");
}

/** callback dispatcher 的 "sess" 分支入口。data = sess:sw:<id> | sess:new */
export async function handleSessionCallback(ctx: Context, data: string): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) {
    await ctx.answerCallbackQuery({ text: "未授權。" }).catch(() => {});
    return;
  }
  const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat.id;
  const userId = ctx.from?.id;
  if (!chatId) {
    await ctx.answerCallbackQuery({ text: "無法辨識 chat。" }).catch(() => {});
    return;
  }
  if (!config.acpSessionResume) {
    await ctx.answerCallbackQuery({ text: FLAG_OFF_HINT }).catch(() => {});
    return;
  }
  const parts = data.split(":");
  const action = parts[1] ?? "";
  const id = parts[2] ?? "";

  // 先摘掉 keyboard 防連點（ASK 同款 pattern）；錯誤時重繪列表恢復操作。
  try {
    await ctx.editMessageReplyMarkup({ reply_markup: undefined });
  } catch { /* keyboard already gone */ }

  if (action === "sw" && id) {
    await ctx.answerCallbackQuery({ text: "切換中…" }).catch(() => {});
    await ctx.reply("🔄 正在切換並恢復 context…（依 adapter 冷啟動速度可能需要一點時間）").catch(() => {});
    try {
      const session = await sessions.switchSession(chatId, id, userId);
      const { sessions: records } = await listSessions(chatId);
      const name = records.find((r) => r.id === id)?.name || id;
      // switchSession 走 resume 路徑；若 adapter session/load 失敗會 fallback
      // fresh（BC-4）——誠實告知 context 未恢復，不假裝成功。
      await ctx.reply(
        session.resumed
          ? `✅ 已切換到「${name}」，原 context 已恢復。`
          : `⚠️ 已切換到「${name}」，但原 context 恢復失敗（adapter 端 session 可能已過期），這是一個全新對話。`,
      );
    } catch (err) {
      await ctx.reply(`❌ 切換失敗：${(err as Error).message}`).catch(() => {});
      const { text, keyboard } = await buildListView(chatId);
      await ctx.reply(text, keyboard ? { reply_markup: keyboard } : undefined).catch(() => {});
    }
    return;
  }

  if (action === "new") {
    await ctx.answerCallbackQuery({ text: "開新對話…" }).catch(() => {});
    try {
      await sessions.newSession(chatId, userId);
      await ctx.reply("✅ 已開新對話（首則訊息會自動命名）。");
    } catch (err) {
      await ctx.reply(`❌ ${(err as Error).message}`).catch(() => {});
    }
    return;
  }

  await ctx.answerCallbackQuery({ text: "未知的動作。" }).catch(() => {});
}

