// ─── Keyboard builders ────────────────────────────────────────────────────────

export function buildHelpMenuKeyboard(): InlineKeyboard {
  const kb = new InlineKeyboard();
  COMMAND_SPECS.forEach((spec, i) => {
    kb.text(spec.button, `help:${spec.name}`);
    if ((i + 1) % 3 === 0) kb.row();
  });
  return kb;
}

export function buildCommandDetailKeyboard(spec: CommandSpec): InlineKeyboard {
  const kb = new InlineKeyboard();
  if (!spec.takesArg) {
    kb.text(`▶ 執行 ${spec.usage}`, `run:${spec.name}`).row();
  }
  kb.text("⬅️ 返回選單", "help:_back");
  return kb;
}

export async function registerBotCommands(bot: Bot): Promise<void> {
  const commands = COMMAND_SPECS.map((spec) => ({
    command: spec.name,
    description: `${spec.button} — ${spec.desc}`
      .replace(/[`*_]/g, "")
      .slice(0, 256),
  }));
  // 先清掉 all_private_chats scope 的殘留指令：該 scope 比 default 更具體、會
  // 遮蔽下面設定的完整選單（曾發生外部程式拿到 token 後寫入 3 個指令蓋掉選單）。
  // 對空 scope 呼叫也回 ok，冪等。若未來要刻意用此 scope 配私聊選單，需移除此行。
  await bot.api.deleteMyCommands({ scope: { type: "all_private_chats" } });
  await bot.api.setMyCommands(commands);
  await bot.api.setChatMenuButton({ menu_button: { type: "commands" } });
}

export function buildReplyKeyboard(): Keyboard {
  const rows: string[][] = [
    ["/help", "/context", "/usage"],
    ["/memory", "/summary", "/MemoryToSkill"],
    ["/wikisync", "/factlint", "/wikilint", "/skilllint", "/dream"],
    ["/sharedsync"],
    ["/save", "/handoff", "/reset", "/cancel"],
    ["/restart", "/hide"],
  ];
  const kb = new Keyboard();
  for (const row of rows) {
    for (const label of row) kb.text(label);
    kb.row();
  }
  return kb.resized().persistent();
}

function escHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

export const HELP_INTRO =
  "<b>指令選單</b> — 點選任一指令即可查看說明。\n" +
  "需要參數的指令（例如 <code>/sendfile &lt;path&gt;</code>）仍請直接輸入。";

export function renderCommandDetail(spec: CommandSpec): string {
  return `<b>${escHtml(spec.usage)}</b>\n${escHtml(spec.desc)}`;
}

// ─── Bot factory with rate-limit observer ─────────────────────────────────────

export type RecoveryListener = () => void | Promise<void>;

export interface BotSetupResult {
  bot: Bot;
  rateLimitedUntil: () => number;
  onRateLimitRecovery: (fn: RecoveryListener) => () => void;
  queuePendingMessage: (chatId: number, text: string) => void;
}

export function createBot(): BotSetupResult {
  const bot = new Bot(config.telegramToken);

  bot.api.config.use(
    autoRetry({
      maxRetryAttempts: 3,
      maxDelaySeconds: config.telegramAutoRetryMaxDelaySeconds,
    })
  );

  let rateLimitedUntil = 0;
  let lastRateLimitSecs = 0;
  let rateLimitChatId: number | undefined;
  let rateLimitRecoveryTimer: NodeJS.Timeout | null = null;
  const pendingMessages: Array<{ chatId: number; text: string }> = [];
  const rateLimitRecoveryListeners: Set<RecoveryListener> = new Set();

  async function flushPendingMessages() {
    const startCount = pendingMessages.length;
    let flushed = 0;
    while (pendingMessages.length > 0) {
      if (rateLimitedUntil > Date.now()) {
        console.warn(
          `[rate-limit] flush paused mid-way: flushed ${flushed}/${startCount}, ${pendingMessages.length} remain`,
        );
        return;
      }
      const { chatId, text } = pendingMessages.shift()!;
      try {
        await bot.api.sendMessage(chatId, text);
        flushed++;
        console.log(`[rate-limit] flushed queued message → chat ${chatId} (${flushed}/${startCount})`);
      } catch (err) {
        console.error("[rate-limit] replay failed, requeueing:", err);
        pendingMessages.unshift({ chatId, text });
        return;
      }
      await new Promise<void>((r) => setTimeout(r, 1100));
    }
    if (startCount > 0) {
      console.log(`[rate-limit] flush complete: ${flushed}/${startCount} delivered`);
    }
  }

  bot.api.config.use(async (prev, method, payload, signal) => {
    const res = await prev(method, payload, signal);
    const retryAfter = (res as any)?.parameters?.retry_after;
    if (typeof retryAfter === "number" && retryAfter > 0) {
      const until = Date.now() + retryAfter * 1000;
      const chatId = Number((payload as any)?.chat_id);
      if (Number.isFinite(chatId)) rateLimitChatId = chatId;
      if (until > rateLimitedUntil) {
        rateLimitedUntil = until;
        if (retryAfter > lastRateLimitSecs) lastRateLimitSecs = retryAfter;
        console.warn(
          `[rate-limit] Telegram 429: retry_after=${retryAfter}s chat=${
            Number.isFinite(chatId) ? chatId : "?"
          } method=${method} — pausing edits until ${new Date(until).toISOString()}`
        );
        if (rateLimitRecoveryTimer) {
          clearTimeout(rateLimitRecoveryTimer);
          rateLimitRecoveryTimer = null;
        }
        const waitMs = until - Date.now() + 500;
        rateLimitRecoveryTimer = setTimeout(async () => {
          rateLimitRecoveryTimer = null;
          const peak = lastRateLimitSecs;
          const target = rateLimitChatId;
          lastRateLimitSecs = 0;
          rateLimitedUntil = 0;
          console.log(
            `[rate-limit] recovered after ${peak}s — flushing ${pendingMessages.length} pending message(s)`
          );
          if (target === undefined) return;
          try {
            await bot.api.sendMessage(
              target,
              `⏳ Telegram 限流解除（等了 ${peak}s）— 現在可以正常收發訊息了。`
            );
          } catch (err) {
            console.error("[rate-limit] failed to send recovery notice:", err);
          }
          for (const fn of Array.from(rateLimitRecoveryListeners)) {
            try {
              await fn();
            } catch (err) {
              console.error("[rate-limit] recovery listener failed:", err);
            }
          }
          await flushPendingMessages();
        }, waitMs);
      }
    }
    return res;
  });

  return {
    bot,
    rateLimitedUntil: () => rateLimitedUntil,
    onRateLimitRecovery(fn: RecoveryListener) {
      rateLimitRecoveryListeners.add(fn);
      return () => rateLimitRecoveryListeners.delete(fn);
    },
    queuePendingMessage(chatId: number, text: string) {
      pendingMessages.push({ chatId, text });
    },
  };
}

